/*
Markup structure required for Embla slider:
Add your own classes to customise styling, but keep the embla__* classes.

<div class="embla">
  <div class="embla__btns">
    <button name="prevButton" type="button" 
      class="embla__btn embla__prev fa-solid fa-chevron-left" 
      aria-label="Previous slide"></button>
    <button name="nextButton" type="button" 
      class="embla__btn embla__next fa-solid fa-chevron-right" 
      aria-label="Next slide"></button>
  </div>
  <div class="embla__viewport">
    <div class="embla__container">
      <div class="embla__slide">
        <!-- Slide content -->
      </div>
      <div class="embla__slide">
        <!-- Slide content -->
      </div>
      <!-- Add more slides as needed -->
    </div>
  </div>
</div>
*/

import EmblaCarousel from 'embla-carousel';
import EmblaCarouselClassNames from 'embla-carousel-class-names';
import { addPrevNextBtnsClickHandlers } from './EmblaCarouselArrowButtons';
import {
    addThumbButtonClickHandlers,
    addToggleThumbButtonsActive,
} from './EmblaCarouselThumbsButton';

const className = 'embla';

function getDataValue(node, key, fallback) {
    //Helper function to get config data attribute values and set defaults.
    const value = node.dataset[key];

    if (value === undefined) {
        return fallback;
    }

    if (value === 'true') return true;
    if (value === 'false') return false;

    if (!Number.isNaN(Number(value)) && value.trim() !== '') {
        return Number(value);
    }

    return value;
}

function launch(emblaNode) {
    const DEFAULT_IN_VIEW_THRESHOLD = 0.9;
    const container = emblaNode.closest('[data-carousel-container]');
    const emblaSlides = emblaNode.querySelectorAll('.embla__slide');

    let thumbsNode = null;
    if (container) {
        // Check if there's a thumbnav
        thumbsNode = container.querySelector('[data-carousel-thumbs]');
    }

    const createThumbs = getDataValue(emblaNode, 'carouselCreateThumbs', false);

    if (createThumbs) {
        thumbsNode = document.createElement('div');
        thumbsNode.className = 'embla-thumbs';
        thumbsNode.setAttribute('data-carousel-thumbs', '');

        thumbsNode.innerHTML = `
            <div class="embla-thumbs__viewport">
                <div class="embla-thumbs__container"></div>
            </div>
        `;

        const thumbsContainer = thumbsNode.querySelector(
            '.embla-thumbs__container'
        );

        emblaSlides.forEach((slide, index) => {
            const thumbSrc = slide.getAttribute('data-carousel-thumb-src');

            const thumbSlide = document.createElement('div');
            thumbSlide.className = 'embla-thumbs__slide';

            if (index === 0) {
                thumbSlide.classList.add('embla-thumbs__slide--selected');
            }

            if (thumbSrc) {
                thumbSlide.innerHTML = `
                    <img src="${thumbSrc}" alt="">
                `;
            }

            thumbsContainer.appendChild(thumbSlide);
        });
        // Insert thumbs directly after emblaNode
        emblaNode.insertAdjacentElement('afterend', thumbsNode);
    }

    //Set options up so they can be controlled by data attributes on the slider
    const OPTIONS = {
        slidesToScroll: getDataValue(emblaNode, 'slidesToScroll', 1),
        align: getDataValue(emblaNode, 'align', 'start'),
        loop: getDataValue(emblaNode, 'loop', false),
        inViewThreshold: getDataValue(
            emblaNode,
            'inViewThreshold',
            DEFAULT_IN_VIEW_THRESHOLD
        ),
    };

    const emblaClassNames = EmblaCarouselClassNames({
        selected: 'embla__slide--is-selected',
        inView: 'embla__slide--is-in-view',
        snap: 'embla__slide--is-snapped',
    });

    const viewportNode = emblaNode.querySelector('.embla__viewport');
    const prevBtn = emblaNode.querySelector('.embla__prev');
    const nextBtn = emblaNode.querySelector('.embla__next');
    const mainSlider = EmblaCarousel(viewportNode, OPTIONS, [emblaClassNames]);

    const removePrevNextBtnsClickHandlers = addPrevNextBtnsClickHandlers(
        mainSlider,
        prevBtn,
        nextBtn
    );

    const slidesInView = () => {
        const inView = new Set(mainSlider.slidesInView());
        const selected = mainSlider.selectedScrollSnap();
        mainSlider.slideNodes().forEach((slide, idx) => {
            slide.setAttribute(
                'aria-hidden',
                inView.has(idx) ? 'false' : 'true'
            );
            slide.setAttribute('tabindex', idx === selected ? '0' : '-1');
        });
    };

    mainSlider
        .on('init', slidesInView)
        .on('reInit', slidesInView)
        .on('slidesInView', slidesInView);

    mainSlider.on('destroy', removePrevNextBtnsClickHandlers);

    if (thumbsNode) {
        const thumbsViewport = thumbsNode.querySelector(
            '.embla-thumbs__viewport'
        );
        const sldierThumbs = EmblaCarousel(thumbsViewport, {
            containScroll: 'keepSnaps',
            dragFree: true,
        });

        addThumbButtonClickHandlers(mainSlider, sldierThumbs);
        addToggleThumbButtonsActive(mainSlider, sldierThumbs);
    }
}

export default {
    launchFn: launch,
    launchQuery: `.${className}`,
};
